svg.script:
{
  "@context": "https://schema.org",
  "@type": "HowTo",
  "name": "Bounce Handling Decision Tree",
  "description": "How to classify and handle email bounces to protect sender reputation and maintain list hygiene.",
  "publisher": {
    "@type": "Organization",
    "name": "InboxAlly",
    "url": "https://www.inboxally.com"
  },
  "step": [
    {
      "@type": "HowToStep",
      "position": 1,
      "name": "Classify the Bounce",
      "text": "When an SMTP failure response is received, classify the bounce by its response code: 5xx codes indicate hard (permanent) bounces, 4xx codes indicate soft (temporary) bounces, and policy or reputation rejections indicate block bounces."
    },
    {
      "@type": "HowToStep",
      "position": 2,
      "name": "Handle Hard Bounces",
      "text": "Hard bounces (550 invalid address, 551 user not found, 552 mailbox disabled, 553 domain not found) are permanent failures. Suppress the address immediately — do not retry. Continued sending to hard-bounced addresses damages sender reputation."
    },
    {
      "@type": "HowToStep",
      "position": 3,
      "name": "Handle Soft Bounces",
      "text": "Soft bounces include mailbox full (452), rate limited (421), DNS timeout (450), and server unavailable (451). Retry delivery up to 3 times over 72 hours. If the address is still failing after retries, suppress it."
    },
    {
      "@type": "HowToStep",
      "position": 4,
      "name": "Handle Block Bounces",
      "text": "Block bounces include content rejection (message flagged by filters), IP or domain blocklisting, DMARC policy rejection (p=reject), and rate throttling. Each requires specific investigation: fix content triggers, request delisting, correct authentication, or reduce sending rate."
    },
    {
      "@type": "HowToStep",
      "position": 5,
      "name": "Monitor Reputation Impact",
      "text": "All bounce types affect sender reputation. Hard bounce rates above 2% cause immediate reputation damage. Persistent soft bounces signal list hygiene problems. Keep total bounce rate below 2% to maintain healthy inbox placement."
    }
  ]
}
